from itertools import permutations

class Solution:
    def numOfWays(self, nums):
        MOD = 10 ** 9 + 7

        def insert(node, v):
            if node is None:
                return [v, None, None]
            if v < node[0]:
                node[1] = insert(node[1], v)
            else:
                node[2] = insert(node[2], v)
            return node

        def build(order):
            root = None
            for v in order:
                root = insert(root, v)
            return root

        def same(a, b):
            if a is None or b is None:
                return a is None and b is None
            return a[0] == b[0] and same(a[1], b[1]) and same(a[2], b[2])

        target = build(nums)
        count = 0
        for perm in permutations(nums):
            if same(build(list(perm)), target):
                count += 1
        return (count - 1) % MOD

