class Solution:
    def numOfWays(self, nums):
        MOD = 10 ** 9 + 7
        n = len(nums)
        C = [[0] * (n + 1) for _ in range(n + 1)]
        for i in range(n + 1):
            C[i][0] = 1
            for j in range(1, i + 1):
                C[i][j] = (C[i - 1][j - 1] + C[i - 1][j]) % MOD

        root = None
        for v in nums:
            if root is None:
                root = [v, None, None]
                continue
            cur = root
            while True:
                if v < cur[0]:
                    if cur[1] is None:
                        cur[1] = [v, None, None]
                        break
                    cur = cur[1]
                else:
                    if cur[2] is None:
                        cur[2] = [v, None, None]
                        break
                    cur = cur[2]

        size_of = {}
        ways_of = {}
        stack = [(root, False)]
        while stack:
            node, processed = stack.pop()
            if node is None:
                continue
            if processed:
                left, right = node[1], node[2]
                ls = size_of.get(id(left), 0)
                rs = size_of.get(id(right), 0)
                lw = ways_of.get(id(left), 1)
                rw = ways_of.get(id(right), 1)
                size_of[id(node)] = ls + rs + 1
                ways_of[id(node)] = (C[ls + rs][ls] * lw % MOD) * rw % MOD
            else:
                stack.append((node, True))
                stack.append((node[1], False))
                stack.append((node[2], False))

        total = ways_of.get(id(root), 1)
        return (total - 1) % MOD

