var numOfWays = function(nums) {
    const MOD = 1000000007n;
    const n = nums.length;
    const C = [];
    for (let i = 0; i <= n; i++) {
        C.push(new Array(n + 1).fill(0n));
        C[i][0] = 1n;
        for (let j = 1; j <= i; j++) {
            C[i][j] = (C[i - 1][j - 1] + C[i - 1][j]) % MOD;
        }
    }

    let root = null;
    for (const v of nums) {
        if (root === null) {
            root = { v, left: null, right: null };
            continue;
        }
        let cur = root;
        while (true) {
            if (v < cur.v) {
                if (cur.left === null) { cur.left = { v, left: null, right: null }; break; }
                cur = cur.left;
            } else {
                if (cur.right === null) { cur.right = { v, left: null, right: null }; break; }
                cur = cur.right;
            }
        }
    }

    const sizeOf = new Map();
    const waysOf = new Map();
    const stack = [[root, false]];
    while (stack.length) {
        const [node, processed] = stack.pop();
        if (node === null) continue;
        if (processed) {
            const ls = node.left ? sizeOf.get(node.left) : 0;
            const rs = node.right ? sizeOf.get(node.right) : 0;
            const lw = node.left ? waysOf.get(node.left) : 1n;
            const rw = node.right ? waysOf.get(node.right) : 1n;
            sizeOf.set(node, ls + rs + 1);
            waysOf.set(node, (C[ls + rs][ls] * lw % MOD) * rw % MOD);
        } else {
            stack.push([node, true]);
            stack.push([node.left, false]);
            stack.push([node.right, false]);
        }
    }

    const total = root ? waysOf.get(root) : 1n;
    return Number(((total - 1n) % MOD + MOD) % MOD);
};
